import java.util.Arrays;
import java.util.Comparator;

public class KNearestNeighbors {
 public static int kNearestNeighbors(double[][] trainingSet, double[] queryPoint, int k) {
 double[] distances = new double[trainingSet.length];
 for (int i = 0; i < trainingSet.length; i++) {
 distances[i] = distance(trainingSet[i], queryPoint);
 }
 Integer[] indices = new Integer[trainingSet.length];
 for (int i = 0; i < indices.length; i++) {
 indices[i] = i;
 }
 Arrays.sort(indices, new Comparator<Integer>() {
 @Override
 public int compare(Integer i1, Integer i2) {
 return Double.compare(distances[i1], distances[i2]);
 }
 });
 int[] kLabels = new int[k];
 for (int i = 0; i < k; i++) {
 kLabels[i] = (int) trainingSet[indices[i]][trainingSet[0].length - 1];
 }
 return mostCommon(kLabels);
 }

 private static double distance(double[] a, double[] b) {
 double sum = 0;
 for (int i = 0; i < a.length - 1; i++) {
 sum += Math.pow(a[i] - b[i], 2);
 }
 return Math.sqrt(sum);
 }

 private static int mostCommon(int[] arr) {
 int maxCount = 0;
 int mostCommon = arr[0];
 for (int i = 0; i < arr.length; i++) {
 int count = 0;
 for (int j = 0; j < arr.length; j++) {
 if (arr[i] == arr[j]) {
 count++;
 }
 }
 if (count > maxCount) {
 maxCount = count;
 mostCommon = arr[i];
 }
 }
 return mostCommon;
 }
}
